from flask import Flask, request, jsonify
from web3 import Web3
import os

app = Flask(__name__)

# Initialize Web3
w3 = Web3(Web3.HTTPProvider(os.getenv('INFURA_URL')))

# Allowed addresses (example)
ALLOWED_ADDRESSES = set([
    '0xYourAllowedAddress1',
    '0xYourAllowedAddress2'
])

def is_valid_signature(message, signature, address):
    try:
        # Hash the message
        message_hash = w3.keccak(text=message)
        
        # Recover the address from the signature
        recovered_address = w3.eth.account.recoverHash(message_hash, signature=signature)
        
        # Check if the recovered address matches the provided address
        return recovered_address.lower() == address.lower()
    except Exception as e:
        # Log the exception securely (avoid sensitive data in logs)
        print(f"Error verifying signature: {str(e)}")
        return False

@app.route('/verify-signature', methods=['POST'])
def verify_signature():
    try:
        data = request.get_json()
        
        # Validate input
        if not data or 'message' not in data or 'signature' not in data or 'address' not in data:
            return jsonify({'error': 'Invalid input'}), 400
        
        message = data['message']
        signature = data['signature']
        address = data['address']
        
        # Check if the address is allowed
        if address not in ALLOWED_ADDRESSES:
            return jsonify({'error': 'Address not allowed'}), 403
        
        # Verify the signature
        if is_valid_signature(message, signature, address):
            return jsonify({'success': True}), 200
        else:
            return jsonify({'error': 'Invalid signature'}), 401
    
    except Exception as e:
        # Log the exception securely (avoid sensitive data in logs)
        print(f"Error processing request: {str(e)}")
        return jsonify({'error': 'Internal server error'}), 500

